import java.util.*;public class Main {    public static void main(String[] args) {        Scanner sc = new Scanner (System.in);        int t=sc.nextInt();        while(t-->0){            int n=sc.nextInt();            sc.nextLine();            String s1=sc.nextLine();            String s2=sc.nextLine();            int f=1;            for(int i=0;i<n;i++){                if(s1.charAt(i)!=s2.charAt(i)&&!((s1.charAt(i)=='B'&&s2.charAt(i)=='G')||(s1.charAt(i)=='G'&&s2.charAt(i)=='B'))){                    f=0;                    break;                }            }            if(f==1){                System.out.println("YES");            }else{                System.out.println("NO");            }        }    }}